export const CONSTANTS = {
  GAME_WIDTH: 540,
  GAME_HEIGHT: 960,
  PLAYER_SPEED: 300,
  PLAYER_FIRE_RATE: 200, // 每多少毫秒发射一次
  BULLET_SPEED: 500,
  ENEMY_BULLET_SPEED: 300,
  ENEMY_BASE_SPEED: 100,
  ENEMY_SPAWN_RATE: 1500, // 初始生成频率
};

export const ENEMY_TYPES = {
  NORMAL: {
    key: 'ships',
    frame: 9,
    score: 10,
    hp: 1,
    speed: 150,
    fireRate: 2000, // 会发射子弹
    scale: 1,
  },
  FAST: {
    key: 'ships',
    frame: 5,
    score: 20,
    hp: 1,
    speed: 250,
    fireRate: 0, // 不发子弹
    scale: 1,
  },
  HEAVY: {
    key: 'ships',
    frame: 1,
    score: 30,
    hp: 3,
    speed: 80,
    fireRate: 1500,
    scale: 1.2,
  }
};

import { create } from 'zustand';

interface GameState {
  score: number;
  isGameOver: boolean;
  addScore: (points: number) => void;
  resetGame: () => void;
  setGameOver: (over: boolean) => void;
}

export const useGameStore = create<GameState>((set) => ({
  score: 0,
  isGameOver: false,
  addScore: (points) => set((state) => ({ score: state.score + points })),
  resetGame: () => set({ score: 0, isGameOver: false }),
  setGameOver: (over) => set({ isGameOver: over }),
}));

import shipsImage from '../assets/pixel-plane-shmup/Tilemap/ships_packed (128x192)[frames=1].png';
import tilesImage from '../assets/pixel-plane-shmup/Tilemap/tiles_packed (192x160)[frames=1].png';
import bgImage from '../assets/pixel-plane-shmup/Tilemap/background.png';

export const ASSETS = {
  ships: shipsImage,
  tiles: tilesImage,
  background: bgImage
};

import { Scene } from 'phaser';
import { ASSETS } from '../assets';

export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // 处理图片加载失败的回调（规则要求）
    this.load.on('loaderror', (file: any) => {
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, 32, 32);
      g.destroy();
    });

    this.load.spritesheet('ships', ASSETS.ships, {
      frameWidth: 32,
      frameHeight: 32,
      spacing: 1
    });

    this.load.spritesheet('tiles', ASSETS.tiles, {
      frameWidth: 16,
      frameHeight: 16,
      spacing: 1
    });

    this.load.image('background', ASSETS.background);

    // 生成简单的音效备用 (如果没有外部资源，用 base64 或者生成波形，这里可以先用 phaser synth 稍后或者仅在游戏中发音)
  }

  create() {
    // 爆炸动画
    this.anims.create({
      key: 'explode',
      frames: this.anims.generateFrameNumbers('tiles', { frames: [4, 5, 6, 7] }),
      frameRate: 12,
      repeat: 0
    });

    this.scene.start('MainGame');
  }
}

