private crashEnemy(playerObj: any, enemyObj: any) {
  if (this.isGameOver) return;
  const enemy = enemyObj as Phaser.Physics.Arcade.Sprite;

  const boom = this.add.sprite(enemy.x, enemy.y, 'tiles', 4);
